    mathSolution: "Aggregation - child can exist independently.",
    codeSolution: "using System;\nusing System.Collections.Generic;\n\nclass Student\n{\n    public string Name { get; set; }\n    \n    public Student(string name)\n    {\n        Name = name;\n    }\n}\n\nclass Department\n{\n    public string Name { get; set; }\n    public List<Student> Students { get; set; } // Aggregation\n    \n    public Department(string name)\n    {\n        Name = name;\n        Students = new List<Student>();\n    }\n    \n    public void AddStudent(Student student)\n    {\n        Students.Add(student);\n        Console.WriteLine($\"{student.Name} added to {Name}\");\n    }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        Student student1 = new Student(\"Alice\");\n        Student student2 = new Student(\"Bob\");\n        \n        Department cs = new Department(\"Computer Science\");\n        cs.AddStudent(student1);\n        cs.AddStudent(student2);\n        \n        // Students exist even if department is destroyed\n        Console.WriteLine($\"Student {student1.Name} still exists\");\n    }\n}",
