    question: "Demonstrate polymorphism with return types using factory method pattern.",
    mathSolution: "Factory methods return base type, actual objects are derived.",
    codeSolution: "using System;\n\ninterface IProduct\n{\n    void Operation();\n}\n\nclass ConcreteProductA : IProduct\n{\n    public void Operation()\n    {\n        Console.WriteLine(\"Product A operation\");\n    }\n}\n\nclass ConcreteProductB : IProduct\n{\n    public void Operation()\n    {\n        Console.WriteLine(\"Product B operation\");\n    }\n}\n\nclass Factory\n{\n    public static IProduct CreateProduct(string type)\n    {\n        switch (type.ToLower())\n        {\n            case \"a\": return new ConcreteProductA();\n            case \"b\": return new ConcreteProductB();\n            default: throw new ArgumentException(\"Invalid type\");\n        }\n    }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        IProduct product1 = Factory.CreateProduct(\"A\");\n        IProduct product2 = Factory.CreateProduct(\"B\");\n        \n        product1.Operation();\n        product2.Operation();\n    }\n}",
    hint: "Factory returns interface/abstract class type.",
