    question: "Demonstrate single responsibility principle with refactoring.",
    mathSolution: "Each class should have one reason to change.",
    codeSolution: "using System;\nusing System.IO;\n\n// Bad: Class with multiple responsibilities\n// class Report\n// {\n//     public void Generate() { }\n//     public void SaveToFile() { }\n//     public void SendEmail() { }\n// }\n\n// Good: Separated responsibilities\nclass ReportGenerator\n{\n    public string Generate()\n    {\n        return \"Report content\";\n    }\n}\n\nclass ReportSaver\n{\n    public void SaveToFile(string content, string filename)\n    {\n        File.WriteAllText(filename, content);\n        Console.WriteLine($\"Report saved to {filename}\");\n    }\n}\n\nclass EmailSender\n{\n    public void SendEmail(string content, string email)\n    {\n        Console.WriteLine($\"Sending report to {email}\");\n        Console.WriteLine($\"Content: {content}\");\n    }\n}\n\nclass Program\n{\n    static void Main()\n    {\n        ReportGenerator generator = new ReportGenerator();\n        ReportSaver saver = new ReportSaver();\n        EmailSender email = new EmailSender();\n        \n        string report = generator.Generate();\n        saver.SaveToFile(report, \"report.txt\");\n        email.SendEmail(report, \"admin@example.com\");\n    }\n}",
    hint: "Each class should have a single, well-defined responsibility.",
